import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import Login from './components/Login';
import AdminLogin from './components/AdminLogin';
import CustomerDashboard from './components/CustomerDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import AdminDashboard from './components/AdminDashboard';
import './App.css';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const handleLogin = (userData) => {
    setUser(userData);
    localStorage.setItem('user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('user');
    localStorage.removeItem('token');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-orange-400 via-red-500 to-pink-500 flex items-center justify-center">
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          className="text-6xl"
        >
          🍔
        </motion.div>
      </div>
    );
  }

  return (
    <Router>
      <MainRoutes user={user} handleLogin={handleLogin} handleLogout={handleLogout} />
    </Router>
  );
}

// ⬇️ Split out the routes and handle redirects safely with useEffect
function MainRoutes({ user, handleLogin, handleLogout }) {
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    // Redirect user only once when role changes or first login
    if (user) {
      if (user.role === 'ADMIN' && location.pathname === '/') navigate('/admin-dashboard');
      else if (user.role === 'OWNER' && location.pathname === '/') navigate('/owner-dashboard');
      else if (user.role === 'CUSTOMER' && location.pathname === '/') navigate('/customer-dashboard');
    }
  }, [user, navigate, location.pathname]);

  return (
    <Routes>
      <Route path="/" element={
        user ? <Navigate to={`/${user.role.toLowerCase()}-dashboard`} replace /> : <Login onLogin={handleLogin} />
      } />
      <Route path="/login" element={<Login onLogin={handleLogin} />} />
      <Route path="/admin-login" element={<AdminLogin onLogin={handleLogin} />} />
      <Route path="/customer-dashboard" element={
        user?.role === 'CUSTOMER' ? <CustomerDashboard user={user} onLogout={handleLogout} /> : <Navigate to="/login" replace />
      } />
      <Route path="/owner-dashboard" element={
        user?.role === 'OWNER' ? <OwnerDashboard user={user} onLogout={handleLogout} /> : <Navigate to="/login" replace />
      } />
      <Route path="/admin-dashboard" element={
        user?.role === 'ADMIN' ? <AdminDashboard user={user} onLogout={handleLogout} /> : <Navigate to="/admin-login" replace />
      } />
    </Routes>
  );
}

export default App;
